<?php
 namespace WPAICG\Core\TokenManager\Reset; if (!defined('ABSPATH')) { exit; } function IsResetDueLogic(int $last_reset_timestamp, string $period): bool { if ($period === 'never' || $last_reset_timestamp <= 0) { return false; } $current_time = time(); $site_timezone = wp_timezone(); $last_reset_dt = new \DateTimeImmutable('@' . $last_reset_timestamp); $last_reset_dt = $last_reset_dt->setTimezone($site_timezone); $next_reset_dt = null; switch ($period) { case 'daily': $next_reset_dt = $last_reset_dt->setTime(0, 0, 0)->modify('+1 day'); break; case 'weekly': $start_of_week = (int) get_option('start_of_week', 1); $day_names = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday']; $start_of_week_name = $day_names[$start_of_week]; $start_of_last_period = clone $last_reset_dt; if ((int)$start_of_last_period->format('w') !== $start_of_week) { $start_of_last_period = $start_of_last_period->modify('last ' . $start_of_week_name); } $next_reset_dt = $start_of_last_period->setTime(0, 0, 0)->modify('+1 week'); break; case 'monthly': $next_reset_dt = $last_reset_dt->setTime(0, 0, 0)->modify('first day of next month'); break; default: return false; } if ($next_reset_dt === null) { return false; } $next_reset_timestamp = $next_reset_dt->getTimestamp(); return $current_time >= $next_reset_timestamp; }